var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"작전 준비가 끝났습니다, 당주님.","JPN":"ご当主、作戦準備が整いました。","ENG":"We’re ready to launch the plan, Lady Nanahara.","TWN":"堂主，作戰準備就緒。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"이 계획만 성공하면 오로치는 봉인과 함께 영원히 현실세계에서 격리되겠죠.","JPN":"この計画さえ成功すれば、オロチは封印され、現実世界から永遠に隔離されるでしょう。","ENG":"If we succeed, Orochi will be separated from the Normalside forever.","TWN":"只要這次計劃成功，大蛇就會和封印一起永遠被隔離在現實世界之外。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"보이시나요? 오랫동안 뿔뿔이 흩어졌던 연합이, 당주님의 뜻에 따라 다시 하나로 뭉쳤습니다.","JPN":"見えますか？　長い間分裂していた連合が、七原家当主の意思によって再び団結しました。","ENG":"Do you see this? All the families who left the Alliance have gathered here to help you.","TWN":"堂主有看到嗎？長久以來如一盤散沙的聯盟，現在照著堂主的意思又再次團結起來。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"모두가 당주님을 믿고 평화를 위해 싸우기로 결심한 겁니다.","JPN":"皆がご当主様を信じて、平和のために戦うことを決意したのです。","ENG":"They are ready to fight for everlasting peace, believing in you.","TWN":"所有人都下定決心要相信堂主，並且為和平而戰。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……고마워요, 카토리 당주.","JPN":"……ありがとうございます、香取家当主。","ENG":"Thank you, Mr. Katori.","TWN":"……謝謝你，香取堂主。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"모두들. 이렇게 한 자리에 모여주어 고맙습니다.","JPN":"皆様、お集まりいただきありがとうございます。","ENG":"I thank you all for coming.","TWN":"首先，謝謝大家齊聚在這裡。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"선조 때부터 이어져 온 이 오랜 의무도, 이젠 매듭을 지을 때가 왔어요.","JPN":"先祖代々伝えられてきた義務をようやく果たす時が来ました。","ENG":"The duty that has been handed down to us through generations will be finally over.","TWN":"長久以來從祖先傳承至今的義務，現在終於要畫下句點。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오로치는 봉인과 함께, 나락으로 떨어질 것입니다.","JPN":"オロチは封印と共に、奈落に落ちるでしょう。","ENG":"We will send Orochi to the netherworld forever, along with its seal.","TWN":"大蛇將和封印一起落入地獄。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니 여러분은 저를 믿고 따라주세요.","JPN":"皆様、どうか私を信じて付いてきてください。","ENG":"So everyone, please follow my command.","TWN":"請大家相信並且跟隨我。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>모두가 널 믿었지.</color>","JPN":"<color=#ff3636>皆がお前を信じた。</color>","ENG":"<color=#ff3636>Everyone trusted you.</color>","TWN":"<color=#ff3636>大家當然相信你。</color>"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>아니, 그들은 너의 어리석은 예언을 믿었을 뿐이야.</color>","JPN":"<color=#ff3636>いや、彼らは愚かなお前の予言を信じただけだ。</color>","ENG":"<color=#ff3636>No, they trusted your stupid prophecy.</color>","TWN":"<color=#ff3636>不對，他們信的是你愚蠢預言。</color>"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>그리고, 결말은 처참했지.</color>","JPN":"<color=#ff3636>そして、結末は凄惨だった。</color>","ENG":"<color=#ff3636>And in the end, it was horror.</color>","TWN":"<color=#ff3636>然而，結局很悽慘。</color>"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"저, 저 좀 살려주십시오! 당주님!","JPN":"た、助けてください！　ご当主！","ENG":"H-help me, Lady Nanahara!","TWN":" 堂主！救…救命！"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"이럴 수는 없어. 하필이면 지금 독기가 쏟아져나온다고? 이건 예견과 다르잖아!","JPN":"ありえない。どうして今になって毒が溢れだすんだ？　予言と違うじゃないか！","ENG":"How can it be? Poison pouring out at this time? It’s different from the prophecy!","TWN":"怎麼會這樣？毒氣怎麼會偏偏現在洩出來？這跟預言不一樣啊！"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>말라 바스러지는 갈대처럼.</color>","JPN":"<color=#ff3636>まるで枯れ朽ちていく葦の如く。</color>","ENG":"<color=#ff3636>Like withering weeds.</color>","TWN":"<color=#ff3636>像乾枯的蘆葦一樣。</color>"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>너를 믿었던 가련한 이들은 네 눈앞에서 시들고 말았지.</color>","JPN":"<color=#ff3636>お前を信じた可哀そうな人間どもは、お前の目の前で散っていった。</color>","ENG":"<color=#ff3636>Those who trusted you withered away, right in front of you.</color>","TWN":"<color=#ff3636>那些相信你的可憐人，在你眼前枯萎。</color>"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……안 돼. 어째서 봉인이.","JPN":"……そんな。どうして封印が。","ENG":"No way... How come the seal is…","TWN":"……不可以，封印為何！"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"},{"id":"L33_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"예정은 실패했습니다. 어서 피하셔야 합니다, 당주님.","JPN":"封印は失敗しました。すぐに安全な場所へ避難してください、ご当主。","ENG":"The plan has failed. We have to evacuate, Lady Nanahara.","TWN":"計劃失敗，堂主，趕緊撤退吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"카토리 당주는요? 언제나처럼 그대가 앞장서십시오. 제가 사람들과 함께 뒤를 따르겠습니다.","JPN":"香取家当主は？　いつものように先頭に立ってください。私は他の皆様と後ろからついていきます。","ENG":"What about you, Mr. Katori? You go ahead. I’ll follow you along with the others.","TWN":"香取堂主呢？像往常一樣，由你帶頭，我和大家一起跟在後面。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"아뇨. 무너진 봉인을 두고 떠나면 오로치는 곧장 현실로 들이닥칠 겁니다.","JPN":"いいえ。崩れた封印を放っておくわけにはいきません。\\nオロチはすぐに現実世界へやってくるでしょう。","ENG":"No. If we leave the seal as is, Orochi will enter into the Normalside.","TWN":"不，不能就這樣放著崩壞的封印不管，我怕大蛇立刻來到現世。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"……제가 카미이즈미와 함께 시간을 벌겠습니다.","JPN":"……私が上泉と共に時間を稼ぎます。","ENG":"I’ll buy you some time with Kamiizumi.","TWN":"……我要和上泉一起爭取時間。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"아뇨, 그럴 수는 없어요! 연합에 그대가 없으면 누가 그 역할을 대신하나요?","JPN":"いいえ、いけません！　貴方がいなくなったら誰がその役目を代わるというのですか？","ENG":"I can’t let you do that! The Alliance needs you!","TWN":"不，不可以！沒有人能夠代替你在聯盟的位置！"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"차라리 제가 남아서 봉인을 수복하겠습니다.","JPN":"私が残り、封印を修復します。","ENG":"I will stay here and restore the seal.","TWN":"不如我留下來恢復封印。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"하하, 그럴 필요는 없습니다.","JPN":"ハハハ、その必要はありません。","ENG":"Hah hah, that won’t be necessary.","TWN":"哈哈，不需要。"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"저에겐 저를 대신해줄 믿음직한 아들이 있으니까요.","JPN":"私には、私の代わりとなってくれる立派な息子がいますから。","ENG":"I have a son who will replace me.","TWN":"我還有可靠的兒子可以代替我！"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"치후유! 나나하라 당주님을 부탁하네!","JPN":"千冬！　ご当主を頼んだぞ！","ENG":"Chifuyu! Take her away from here!","TWN":"千冬！七原堂主就拜託你了！"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님, 빠져나가려면 서두르셔야 합니다!","JPN":"当主、お急ぎください！","ENG":"Lady Nanahara, we have to go now!","TWN":"堂主，趕緊撤退吧！"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"안 돼!","JPN":"だめよ！","ENG":"No!","TWN":"不可以！"},"stage":{"bg":"REEDS_FIELD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"당주님!","JPN":"ご当主！","ENG":"Lady!","TWN":"堂主！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"괜찮으십니까, 당주님?","JPN":"気が付きましたか、ご当主？","ENG":"Are you alright?","TWN":"堂主，您還好嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네? 여긴……","JPN":"え？　ここは……","ENG":"Huh? Where am I...","TWN":"嗯？這裡是……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저에게 무슨 일이 있었던 거죠?","JPN":"私にいったい何があったのですか？","ENG":"What happened to me?","TWN":"我發生了什麼事？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"제8 봉인역입니다. 무너진 봉인석을 복원하기 위해 독기를 제거하다가 쓰러지셨습니다.","JPN":"第八封印域です。\\n崩れた封印石を復元するために、毒を除去している最中にお倒れになりました。","ENG":"This is the 8th Seal Domain. You fainted while removing the poison from the broken seal.","TWN":"這裡是第8封印域，您為了要修復崩塌的封印石，在去除毒氣的過程中暈倒了。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그랬었죠. 현재 침식파 계수기의 반응은 어떤가요?","JPN":"そうでしたね。現在の侵食波計数機の反応はどうですか？","ENG":"I remember now. What is the reading on the Corruption Ray counter?","TWN":"我想起來了。那現在侵蝕波計數器的反應如何？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"아, CSE레벨은 1단계에서 멈췄습니다. 당주님께서 행하신 정화 작업이 확실히 효과를 보고 있군요.","JPN":"はっ、CSEレベルは第1段階で止まっています。\\nご当主の浄化作業が確実に効果を出しているようです。","ENG":"The CSE level stopped at 1. I think your purification is actually working.","TWN":"是，CSE等級停在第1階，堂主剛才的淨化作業，確實有發揮效果。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다행입니다. 이걸로 시간을……","JPN":"よかったです。ではこれで時間を……","ENG":"That’s good. This will buy us some time...","TWN":"那就好，那時間……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……으윽.","JPN":"……ううっ！","ENG":"Ugh...","TWN":"……呃呃。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"당주님!","JPN":"ご当主！","ENG":"Lady!","TWN":"堂主！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"전…… 괜찮아요.","JPN":"私は……大丈夫です。","ENG":"I'm... I'm fine.","TWN":"我…… 沒事。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"언제까지 이렇게 혼자 무리하실 겁니까?","JPN":"いつまでご無理をされるつもりなのですか？","ENG":"You can’t exert yourself like this forever.","TWN":"您要一個人硬撐到什麼時候？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"하야미의 일만 아니었어도, 다른 당주들이 저흴 도왔을 텐데요.","JPN":"速水のことさえなければ、他の当主の皆様も私たちに協力してくれたはずです。","ENG":"The other families would have helped us if it wasn’t for Hayami.","TWN":"要不是因為速水早苗的事，其他堂主一定會一起幫我們。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"지금이라도 그 여자를 내치시는 편이……","JPN":"今からでもあの女を追い出したほうが……","ENG":"Please, banish her before it gets worse...","TWN":"現在還來得及，快把那個女人趕出去……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"괜찮아요!","JPN":"大丈夫です！","ENG":"I’m okay!","TWN":"我沒事！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이 정도는……! 도움이 없어도 저 혼자 감당할 수 있습니다!","JPN":"これくらい……！　助けがなくても私一人で耐えられます！","ENG":"I can take it. I don’t need help. I can handle it myself!","TWN":"這點程度…！不用別人幫忙，我自己可以的！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니, 제발…… 함께 싸워야 할 서로를 미워하지 마세요.","JPN":"だからどうか……共に戦う仲間を憎むのはおやめください。","ENG":"So, please... Stop hating each other when we should be joining hands.","TWN":"所以拜託你……我們應該要一起努力，而不是內鬨。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"당주님……?","JPN":"ご当主……？","ENG":"Lady Nanahara?","TWN":"堂主……？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미안합니다. 점잖지 못한 모습을 보여서…….","JPN":"申し訳ございません。少々取り乱してしまいました……","ENG":"I am sorry, I was being disgraceful.","TWN":"抱歉，我失態了…"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"여기 계셨군요, 당주님.","JPN":"こちらにいらっしゃいましたか、当主。","ENG":"Lady Nanahara, you are here.","TWN":"堂主，原來您在這裡！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……치후유?","JPN":"……千冬？","ENG":"Chifuyu?","TWN":"……千冬？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"돌아가렴. 지금 네가 날 찾아오면 장로들이 좋지 않게 생각할 거야.","JPN":"戻りなさい。貴方がここに来たことを長老たちに知られたら良くないわ。","ENG":"Go back. The elders won’t like it if they know you’re here.","TWN":"你回去吧。你來找我，長老們會不高興的。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님께서 직접 확인해보셔야 할 일이 있습니다.","JPN":"当主に直接ご確認いただきたいことがあります。","ENG":"There’s something you have to see for yourself.","TWN":"有事情需要請堂主親自確認。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"벌써 재의결을 할 시간이 됐니?","JPN":"もう再議決の時間なの？","ENG":"Is it time for the meeting already?","TWN":"要重新表決了嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그 이야기는 아직입니다만……","JPN":"いいえ、その話ではなく……","ENG":"No, it’s not that...","TWN":"還沒提到這件事……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님을 노리던 암살자 잔당을 잡았습니다.","JPN":"当主を狙っていた暗殺者の残党を捕らえました。","ENG":"We caught the rest of the assassins.","TWN":"抓到想要對堂主不利的刺客同夥了。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"심문 중에 하야미 사나에의 이름을 말했다고 하더군요.","JPN":"尋問中に速水早苗の名を吐いたそうです。","ENG":"They mentioned Hayami Sanae during the interrogation.","TWN":"據說在審問時有提到速水早苗的名字。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};